-- Sport/active venue candidates -> real (unpublished) venues rows.
-- Generated from data/data-ops/{canggu-sport-leads,other-districts-sport-leads}/*.json
-- 189 rows total (source: Canggu 48 + other districts 143;
-- 2 exact same-business duplicates removed —
-- see git history of this generator for the dedup rule).
--
-- IMPORTANT — read before running:
-- 1. publication_status is set to 'review' (NOT 'published') on every row.
--    Per supabase/migrations/0018_uluwatu_launch.sql, 'review' = internal
--    only / noindex; 'published' = live, evidence-backed, indexed. These
--    rows have NOT been through an editorial/on-the-ground verification
--    pass (why_its_here/best_for are intentionally left NULL — no invented
--    editorial copy, per AGENTS.md guardrail #10), and roughly a third of
--    them have no confirmed website/Instagram at all. Flipping them to
--    'published' in bulk would put unverified information in front of
--    travellers, which is exactly what the publication_status gate exists
--    to prevent.
-- 2. Duplicate-safety: ON CONFLICT (slug) DO NOTHING means a row is
--    skipped (not duplicated, not erroring) if a venue with that exact
--    slug already exists. This is a mechanical, exact-slug-only check —
--    it will NOT catch the same real business already in the catalogue
--    under a different slug/spelling. No live-catalogue dedup pass was
--    performed against production data (no DB access from the authoring
--    session) — a manual look at existing Canggu/other-district fitness &
--    yoga venues before or after running this is still recommended.
--    Within this file itself: 4 same-business duplicates across district
--    labels were resolved before generating this SQL (3 dropped as exact
--    duplicates, 1 — Rip Curl Surf School, which runs multiple branches —
--    kept as two rows with district-disambiguated slugs).
-- 3. address is NULL for every row — the source lead sheets only had an
--    area label, not a street address; gmaps_url is a generated Maps
--    SEARCH query (name + area + district), not a verified place pin.
-- 4. Google ratings/review counts were intentionally NOT carried into this
--    SQL at all (guardrail #2 — Other Bali never republishes Google
--    review data, not even quietly).
--
-- To make a specific venue visible on the site once you've checked it:
--   update venues set publication_status = 'published', last_verified_at = current_date
--   where slug = '<slug>';

insert into venues
